// =====================================================
// PARSING ANNÉE
// =====================================================

function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a, adText) {
  const d1 = parseYearMonth(getAnnonceYearRaw1(a));
  if (d1.year) return d1.year;

  const d2 = parseYearMonth(getAnnonceYearRaw2(a));
  if (d2.year) return d2.year;

  // Fallback : extraction depuis texte
  const m = String(adText || "").match(/\b(19|20)\d{2}\b/);
  if (m) return parseInt(m[0], 10);

  return 0;
}

// =====================================================
// EXTRACTION CC
// =====================================================

function ccFromHref(href) {
  const s = String(href || "");
  const m = s.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

function extractCCFromText(text) {
  const raw = String(text || "");
  if (!raw.trim()) return 0;

  const noKm = raw.replace(/\b(\d{1,6})\s*km\b/gi, " ");
  const s = normalize(noKm);

  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  m = s.match(/\b(\d{2,4})(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  return 0;
}

function extractNumbers(text) {
  const raw = String(text || "")
    .replace(/\b(\d{1,6})\s*km\b/gi, " ")
    .replace(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/g, " ");
  const s = normalize(raw);
  return (s.match(/\b\d{3,4}\b/g) || []).map(n => parseInt(n, 10));
}

function inferCCFromNumbers(adText, annonceYear) {
  const nums = extractNumbers(adText);
  const candidates = nums.filter(n =>
    n >= 50 && n <= 2500 && (!annonceYear || n !== annonceYear)
  );
  if (!candidates.length) return 0;
  return Math.max(...candidates);
}

function getAnnonceCC(a, adText, annonceYear) {
  // Priorité 1 : href LBC (le plus fiable pour 1st Match)
  const ccH = ccFromHref(getAnnonceCCHref(a));
  // FIX: reject clearly wrong CC values from LBC (> 2500cc or < 30cc for non-scooter)
  if (ccH && ccH <= 2500) return ccH;

  // Priorité 2 : champ texte
  const ccTxt = get(a, "text-body-1 (7)", "vehicule_cc_txt", "CC", "cc");
  const ccField = extractCCFromText(ccTxt);
  if (ccField) return ccField;

  // Priorité 3 : extraction depuis description
  const ccT = extractCCFromText(adText);
  if (ccT) return ccT;

  // Priorité 4 : inférence depuis nombres
  const ccN = inferCCFromNumbers(adText, annonceYear || 0);
  if (ccN) return ccN;

  return 0;
}

// =====================================================
// EXTRACTION BRAND/MODEL DEPUIS HREF
// =====================================================

function decodePlus(s) {
  return String(s || "").replace(/\+/g, " ");
}

function extractBrandFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_brand:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

function extractModelFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_model:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

// =====================================================
// SIMILARITÉ
// =====================================================

function jaccard(aTokens, bTokens) {
  if (!aTokens.length || !bTokens.length) return 0;
  const A = new Set(aTokens);
  const B = new Set(bTokens);
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
}

function coverageSet(adSet, modelTokens) {
  if (!modelTokens.length) return 0;
  // Build compact version of adSet (sans séparateurs)
  const adSetCompact = new Set([...adSet].map(t => t.replace(/[-_]/g, '')));
  function tokenMatches(t) {
    const tc = t.replace(/[-_]/g, '');
    if (adSet.has(t) || adSetCompact.has(tc)) return true;
    // FIX6B-1: substring match (e.g. "r1200" inside "r1200r")
    for (const at of adSetCompact) {
      if (tc.length >= 3 && at.length >= 3 && (at.includes(tc) || tc.includes(at))) return true;
    }
    // FIX6B-2: compound split (sv650 -> sv in ad AND 650 in ad)
    const m = tc.match(/^([a-z]{2,})([0-9]{3,4})([a-z]*)$/);
    if (m) {
      const alpha = m[1], num = m[2], sfx = m[3];
      const alphaOk = adSetCompact.has(alpha) ||
        [...adSetCompact].some(at => at.startsWith(alpha) && at.length <= alpha.length + 2);
      const numOk = adSetCompact.has(num) || adSetCompact.has(num + sfx);
      if (alphaOk && numOk) return true;
    }
    return false;
  }
  let hit = 0;
  for (const t of modelTokens) {
    if (tokenMatches(t)) hit++;
  }
  return hit / modelTokens.length;
}

// =====================================================
// VARIANTS & DOMINANTS
// =====================================================

function modelVariants(modelRaw) {
  const cleaned = String(modelRaw || "").replace(/[|]/g, "/");
  const parts = cleaned.split("/").map(p => p.trim()).filter(Boolean);
  const baseVariants = Array.from(new Set(parts.map(p => normalize(p)).filter(Boolean)));
  const extra = [];
  for (const v of baseVariants) {
    // Variante split lettre-chiffre: "ds625x" -> "ds 625 x"
    const split = v.replace(/([a-z])(\d)/g, '$1 $2').replace(/(\d)([a-z])/g, '$1 $2').replace(/\s+/g, ' ').trim();
    if (split && !baseVariants.includes(split) && !extra.includes(split)) extra.push(split);
    // Variante sans chiffres: "ds625x" -> "dsx"
    const nodig = v.replace(/\d+/g, '').replace(/\s+/g, ' ').trim();
    if (nodig && nodig !== v && nodig.length >= 2 && !baseVariants.includes(nodig) && !extra.includes(nodig)) extra.push(nodig);
    // FIX: variante compacte sans espaces: "f 900 r" -> "f900r" (fix models with single-letter tokens)
    const compact = v.replace(/\s+/g, '');
    if (compact && compact !== v && !baseVariants.includes(compact) && !extra.includes(compact)) extra.push(compact);
  }
  // FIX: partie avant parenthèse: "Z650 (ER-6n)" -> "z650", "V7 (850, new)" -> "v7"
  const beforeParen = normalize(String(modelRaw || "").replace(/\s*\(.*$/g, '').trim());
  if (beforeParen && !baseVariants.includes(beforeParen) && !extra.includes(beforeParen)) extra.push(beforeParen);
  // FIX: contenu entre parenthèses sans préfixe "ex-": "Speed Twin 900 (ex-Street Twin)" -> "street twin"
  const parenMatches = (String(modelRaw || "").match(/\(([^)]+)\)/g) || []);
  for (const pm of parenMatches) {
    const inner = pm.replace(/[()]/g, '').trim().replace(/^ex[-\s]+/i, '').trim();
    if (inner) {
      const cn = normalize(inner);
      if (cn && !baseVariants.includes(cn) && !extra.includes(cn)) extra.push(cn);
    }
  }
  return [...baseVariants, ...extra];
}

function getModelDominantTokens(modelRaw) {
  const n = normalize(modelRaw);
  // Match 3-4 digit numbers with word boundary (ex: "MT 07", "R 1250")
  const nums = n.match(/\b\d{3,4}\b/g) || [];
  if (nums.length) return nums.map(Number);

  // FIX: For compact models like "DS625X" -> "ds625x", extract embedded digits
  // Returns [625] as number -> allows annonceCC comparison in dominants gate
  const embeddedNums = n.match(/\d{3,4}/g) || [];
  if (embeddedNums.length) return embeddedNums.map(Number);

  const toks = tokenize(modelRaw);
  return toks.filter(t => /\d/.test(t) || t.length >= 4);
}

