// ===============================
// HELPERS
// ===============================
const CURRENT_YEAR = 2026;

function extractFavoris(value) {
  if (!value) return 0;
  const m = String(value).match(/(\d+)\s*$/); // prend le dernier nombre
  return m ? parseInt(m[1], 10) : 0;
}
function extractCC(value) {
  if (!value) return "";

  const m = String(value).match(/(\d{2,4}(\.\d+)?)/);
  if (!m) return "";

  const cc = parseFloat(m[1]);

  // ❌ si inférieur à 49.8 → ne rien afficher
  if (cc < 49.8) return "";

  return cc;
}


function extractNbPhotos(value) {
  if (!value) return 0;

  const s = String(value);

  // ex: "Voir les 5 photos" / "Voir les photos" / "Voir 12 photos"
  const m = s.match(/(\d+)/);
  return m ? parseInt(m[1], 10) : 0;
}

/**
 * Parse matched_generations:
 * Exemples possibles:
 * - "SMCR (Gen2) 2021–2024"
 * - "SMCR (Gen2) 2021→"
 * - "(LC) 2018-2020"
 * - "2021→"
 */
function parseGenerations(value) {
  const s = String(value || "").trim();
  if (!s) return { label: "", yStart: "", yEnd: "" };

  // label = contenu entre parenthèses
  const labelMatch = s.match(/\(([^)]+)\)/);
  const label = labelMatch ? labelMatch[1].trim() : "";

  // Range "2002–2003" ou "2002-2003"
  const rangeMatch = s.match(/(\d{4})\s*[-–]\s*(\d{4})/);
  if (rangeMatch) {
    return { label, yStart: Number(rangeMatch[1]), yEnd: Number(rangeMatch[2]) };
  }

  // Arrow "2018→" => fin = année courante
  const arrowMatch = s.match(/(\d{4})\s*→/);
  if (arrowMatch) {
    return { label, yStart: Number(arrowMatch[1]), yEnd: CURRENT_YEAR };
  }

  // Fallback: une seule année
  const oneYear = s.match(/(\d{4})/);
  if (oneYear) {
    const y = Number(oneYear[1]);
    return { label, yStart: y, yEnd: y };
  }

  return { label: "", yStart: "", yEnd: "" };
}

// ===============================
// MAPPING
// ===============================
function mapField(item) {
  const gen = parseGenerations(item.matched_generations);

  return {
    json: {
      // ===============================
      // IDENTITÉ ANNONCE
      // ===============================
      Nom_annonce: item["text-headline-1-expanded"] || item.annonce_title || "",
      Url_Https: item["absolute href"] || item.annonce_url || "",

      // ✅ Favoris (chiffre uniquement)
      "personnes ont déjà ajouté cette annonce en favori": extractFavoris(item["u-shadow-border-transition"]),

"nombre de photos supplémentaires": extractNbPhotos(item["u-shadow-border-transition (2)"]),

      // ===============================
      // DATE / HEURE
      // ===============================
      "Date de mise en publication": item["text-caption"] || "",
      "Heure de mise en publication": item["text-caption (2)"] || "",

      // ===============================
      // PRIX
      // ===============================
      Prix_affiche: item["flex"] || item["text-headline-1"] || "",

      // ===============================
      // ✅ PHOTOS (3 clés récupérées)
      // ===============================
      Photo_1: item["size-full src"] || "",
      Photo_2: item["size-full src (2)"] || "",
      Photo_3: item["size-full src (3)"] || "",

          // ===============================
    // VEHICULE / VENDEUR (RENOMMÉ)
    // ===============================
    "nom du vendeur pro": item["text-body-1"] || "",

    "année du modèle": item["text-body-1 (6)"] || "",

    "Kilométrage": item["text-body-1 (7)"] || "",

    Mise_en_circulation: item["text-body-1 (9)"] || "",
Cylindree_cc: (() => { const href = item["text-body-1 href (5)"] || ""; const m = href.match(/cubic_capacity:(\d+)/); return m ? parseFloat(m[1]) : extractCC(item["text-body-1 (14)"]); })(),

      // ===============================
      // ✅ DESCRIPTION COMPLÈTE
      // ===============================
"Description de l'annonce": item["text-body-1 (17)"] || item.annonce_description || "",

      // ===============================
      // STATUT / VENDEUR
      // ===============================
      Statut_annonce: item["box-border"] || "",

      // ✅ 3 clés récupérées côté vendeur
      Nom_vendeur: item["text-headline-1 (2)"] || "",
      "nombre d’avis": item["text-body-2"] || "",
      "Dernière activité": item["text-body-2 (2)"] || "",

      // (tu peux garder ces noms internes si tu en as encore besoin ailleurs)
      Paiement_ou_SIREN: item["text-body-2"] || "",
      Infos_vendeur: item["text-body-2 (2)"] || "",

      // ===============================
      // MATCHING
      // ===============================
      matched_marque: item.matched_marque || "",
      matched_modele: item.matched_modele || "",
      matched_generations: item.matched_generations || "",

      generation_label: gen.label || "",
      generation_year_start: gen.yStart || "",
      generation_year_end: gen.yEnd || "",

      matched_score: item.matched_score || "",
      matched_quality: item.matched_quality || "",
      needs_review: item.needs_review ?? false,

      // ===============================
      // RÉSULTAT MATCHING (CRITIQUE pour IF node)
      // ===============================
      matched_ok: item.matched_ok ?? false,
      matched_confidence: item.matched_confidence || "NONE",
      matching_engine: item.matching_engine || "",
    }
  };
}

// ===============================
// RUN
// ===============================
return $input.all().map(i => mapField(i.json));

const items = $input.all();

function parsePrix(val) {
  if (!val && val !== 0) return null;
  const m = String(val).replace(/\s/g, '').match(/\d+/);
  return m ? parseInt(m[0], 10) : null;
}
function parseKm(val) {
  if (!val && val !== 0) return null;
  const m = String(val).replace(/\s/g, '').match(/\d+/);
  return m ? parseInt(m[0], 10) : null;
}
function parseAnnee(val) {
  if (!val) return null;
  const m = String(val).match(/\b(19|20)\d{2}\b/);
  return m ? parseInt(m[0], 10) : null;
}
function parseSiren(val) {
  if (!val) return null;
  const m = String(val).match(/\b\d{9}\b/);
  return m ? m[0] : null;
}
function parseScore(val) {
  if (!val && val !== 0) return null;
  const n = parseFloat(val);
  return isNaN(n) ? null : Math.round(n * 1000) / 1000;
}
function parseIntOrNull(val) {
  if (!val && val !== 0) return null;
  const n = parseInt(val, 10);
  return isNaN(n) ? null : n;
}
function parseHeure(val) {
  if (!val) return null;
  const s = String(val).trim();
  return /^\d{2}:\d{2}$/.test(s) ? s : null;
}

return items.map(({ json: item }) => {
  const nomVendeurPro = item['nom du vendeur pro'] || '';
  const siren = parseSiren(item.Paiement_ou_SIREN);
  const vendeurStatut = (nomVendeurPro || siren) ? 'Pro' : 'Particulier';
  const vendeurNom = nomVendeurPro || item.Nom_vendeur || null;

  return {
    json: {
      supabase: {
        // ── Identite annonce ──────────────────────────────
        id:    item.Url_Https || '',
        url:   item.Url_Https || '',
        titre: item.Nom_annonce || null,

        // ── Prix / vehicule ───────────────────────────────
        prix:        parsePrix(item.Prix_affiche),
        kilometrage: parseKm(item['Kilom\u00e9trage']),
        annee:       parseAnnee(item['ann\u00e9e du mod\u00e8le']),
        cylindree:   item.Cylindree_cc ? parseFloat(item.Cylindree_cc) : null,
        mise_en_circulation: item.Mise_en_circulation || null,

        // ── Matching BDD ──────────────────────────────────
        marque:     item.matched_marque || null,
        modele:     item.matched_modele || null,
        generation: item.generation_label || item.matched_generations || null,
        generation_year_start: parseIntOrNull(item.generation_year_start),
        generation_year_end:   parseIntOrNull(item.generation_year_end),

        // ── Qualite du matching ───────────────────────────
        matched_score:      parseScore(item.matched_score),
        matched_confidence: item.matched_confidence || null,
        matched_quality:    item.matched_quality || null,
        matching_engine:    item.matching_engine || null,

        // ── Vendeur ───────────────────────────────────────
        vendeur_nom:    vendeurNom,
        vendeur_statut: vendeurStatut,
        vendeur_siren:  siren,

        // ── Medias ────────────────────────────────────────
        photo1: item.Photo_1 || null,
        photo2: item.Photo_2 || null,
        photo3: item.Photo_3 || null,
        nb_photos_supplementaires: parseInt(item['nombre de photos suppl\u00e9mentaires']) || 0,
        favoris: item['personnes ont d\u00e9j\u00e0 ajout\u00e9 cette annonce en favori'] || 0,

        // ── Publication ───────────────────────────────────
        heure_publication: parseHeure(item['Heure de mise en publication']),

        // ── Contenu ───────────────────────────────────────
        description: item["Description de l'annonce"] || null,
      },
      // Champs preserves pour le IF node
      matched_ok:         item.matched_ok ?? false,
      matched_confidence: item.matched_confidence || 'NONE',
      needs_review:       item.needs_review ?? false,
    }
  };
});
